INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Comment détermine t-on le début de Ramadân ?', 'Harari', 'لا تقَدّموا رمضان بيوم أو يومين صُوموا لِرُؤيَتِهِ وأَفْطِروا لرؤيته فإن غُمَّ عَلَيكُم فَأَكْمِلُوا عِدَّةَ شَعْبَان ثَلاثين يوماً', '', '', 'Cette parole signifie : « N’anticipez pas Ramadân d’un jour ou deux. Jeûnez à la vue [du croissant] et interrompez le jeûne à la vue [du croissant] et si vous ne l’avez pas vue, poursuivez le compte de Cha’bân à trente jours » [rapporté par Al-Boukhâri et Mouslim].
– Et il a dit également (صلى الله عليه وسلم) :', 'abache, abaches, abachi, abachites'
